mapper.select:
SELECT

id,

create_time, update_time,

trace_id, client_id, request_id, request_time, accept_language, path, method, user_agent, host, x_forwarded_for, x_real_ip, referer, session_type, passport_id, user_id, name, admin_user, organ_id, organ_name, organ_type, admin_company, application_id, application_code, application_organ_id, payload,

version
FROM audit_event



        AND id = #{id, jdbcType=BIGINT}


        AND id IN

            #{item, jdbcType=BIGINT}





            AND create_time >= #{createTime[0], jdbcType=TIMESTAMP}


            AND create_time <= #{createTime[1], jdbcType=TIMESTAMP}


            AND create_time BETWEEN #{createTime[0], jdbcType=TIMESTAMP}
            AND #{createTime[1], jdbcType=TIMESTAMP}




            AND update_time >= #{updateTime[0], jdbcType=TIMESTAMP}


            AND update_time <= #{updateTime[1], jdbcType=TIMESTAMP}


            AND update_time BETWEEN #{updateTime[0], jdbcType=TIMESTAMP}
            AND #{updateTime[1], jdbcType=TIMESTAMP}




        AND trace_id = #{traceId, jdbcType=VARCHAR}


        AND client_id = #{clientId, jdbcType=VARCHAR}


        AND request_id = #{requestId, jdbcType=VARCHAR}


        AND request_time = #{requestTime, jdbcType=TIMESTAMP}


        AND accept_language = #{acceptLanguage, jdbcType=VARCHAR}


        AND path = #{path, jdbcType=VARCHAR}


        AND method = #{method, jdbcType=VARCHAR}


        AND user_agent = #{userAgent, jdbcType=VARCHAR}


        AND host = #{host, jdbcType=VARCHAR}


        AND x_forwarded_for = #{xForwardedFor, jdbcType=VARCHAR}


        AND x_real_ip = #{xRealIp, jdbcType=VARCHAR}


        AND referer = #{referer, jdbcType=VARCHAR}


        AND session_type = #{sessionType, jdbcType=VARCHAR}


        AND passport_id = #{passportId, jdbcType=BIGINT}


        AND user_id = #{userId, jdbcType=BIGINT}


        AND name = #{name, jdbcType=VARCHAR}


        AND admin_user = #{adminUser, jdbcType=TINYINT}


        AND organ_id = #{organId, jdbcType=BIGINT}


        AND organ_name = #{organName, jdbcType=VARCHAR}


        AND organ_type = #{organType, jdbcType=VARCHAR}


        AND admin_company = #{adminCompany, jdbcType=TINYINT}


        AND application_id = #{applicationId, jdbcType=BIGINT}


        AND application_code = #{applicationCode, jdbcType=VARCHAR}


        AND application_organ_id = #{applicationOrganId, jdbcType=BIGINT}


        AND payload = #{payload, jdbcType=LONGVARCHAR}
